import{_ as a,c as o,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"授權條款: BSL 條款說明 | Plannotator","description":"學習 Plannotator 的 Business Source License 1.1 (BSL) 授權條款和商業使用限制。了解允許的使用情境、未來變更計畫及 2030 年轉為 Apache 2.0 的時程表。","frontmatter":{"title":"授權條款: BSL 條款說明 | Plannotator","sidebarTitle":"了解商業使用規則","subtitle":"授權條款: BSL 條款說明","description":"學習 Plannotator 的 Business Source License 1.1 (BSL) 授權條款和商業使用限制。了解允許的使用情境、未來變更計畫及 2030 年轉為 Apache 2.0 的時程表。","tags":["授權條款","BSL-1.1","商業使用"],"prerequisite":[],"order":3},"headers":[],"relativePath":"zh-tw/backnotprop/plannotator/appendix/license/index.md","filePath":"zh-tw/backnotprop/plannotator/appendix/license/index.md"}'),n={name:"zh-tw/backnotprop/plannotator/appendix/license/index.md"};function e(i,t,s,d,h,p){return r(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="plannotator-授權條款說明" tabindex="-1">Plannotator 授權條款說明 <a class="header-anchor" href="#plannotator-授權條款說明" aria-label="Permalink to &quot;Plannotator 授權條款說明&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>了解 Plannotator 使用的授權條款類型和核心條款</li><li>明確哪些使用情境是被允許的，哪些是受限的</li><li>知道授權條款的未來變更時程表</li><li>了解如何取得商業授權或聯絡授權方</li></ul><h2 id="你現在需要了解" tabindex="-1">你現在需要了解 <a class="header-anchor" href="#你現在需要了解" aria-label="Permalink to &quot;你現在需要了解&quot;">​</a></h2><p>Plannotator 採用 <strong>Business Source License 1.1 (BSL)</strong> 作為其開源授權條款。這是一種特殊的授權條款，旨在保護商業價值的同時，最終讓專案完全開源。</p><h2 id="核心條款" tabindex="-1">核心條款 <a class="header-anchor" href="#核心條款" aria-label="Permalink to &quot;核心條款&quot;">​</a></h2><h3 id="授權條款類型" tabindex="-1">授權條款類型 <a class="header-anchor" href="#授權條款類型" aria-label="Permalink to &quot;授權條款類型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>內容</th></tr></thead><tbody><tr><td><strong>授權條款名稱</strong></td><td>Business Source License 1.1 (BSL)</td></tr><tr><td><strong>版權方</strong></td><td>backnotprop (2025)</td></tr><tr><td><strong>授權專案</strong></td><td>plannotator</td></tr><tr><td><strong>變更日期</strong></td><td>2030-01-01</td></tr><tr><td><strong>變更後授權條款</strong></td><td>Apache License, Version 2.0</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">什麼是 BSL？</p><p>Business Source License 是一種由 MariaDB 開發的特殊授權條款。它在短期內限制了某些商業用途，但承諾在特定日期後將軟體轉換為完全開源的授權條款（如 Apache 2.0）。這種模式讓開源專案能夠在商業化過程中獲得可持續的收益，同時確保長期對社群開放。</p></div><h3 id="允許的使用方式" tabindex="-1">允許的使用方式 <a class="header-anchor" href="#允許的使用方式" aria-label="Permalink to &quot;允許的使用方式&quot;">​</a></h3><p>根據 BSL 1.1 條款，你可以：</p><ul><li><p>✅ <strong>複製、修改和建立衍生作品</strong></p><ul><li>你可以基於 Plannotator 進行二次開發</li><li>可以修改原始碼以適應你的需求</li></ul></li><li><p>✅ <strong>重新散布</strong></p><ul><li>可以散布原始或修改後的版本</li><li>必須保留原始的授權條款聲明</li></ul></li><li><p>✅ <strong>非正式環境使用</strong></p><ul><li>內部開發、測試和評估</li><li>個人學習和研究</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">個人和企業內部的廣泛使用</p><p>BSL 對「非正式環境使用」的定義很寬泛，包括個人和公司內部的各種情境。你和你的團隊成員（包括獨立承包商）都可以自由使用 Plannotator 進行開發、測試和部署。</p></div><h3 id="使用限制-重要" tabindex="-1">使用限制（重要！） <a class="header-anchor" href="#使用限制-重要" aria-label="Permalink to &quot;使用限制（重要！）&quot;">​</a></h3><p><strong>核心限制</strong>：不得將 Plannotator 用於 <strong>計畫、上下文或審批服務（Planning, Context, or Approval Service）</strong>。</p><h4 id="什麼是「計畫、上下文或審批服務」" tabindex="-1">什麼是「計畫、上下文或審批服務」？ <a class="header-anchor" href="#什麼是「計畫、上下文或審批服務」" aria-label="Permalink to &quot;什麼是「計畫、上下文或審批服務」？&quot;">​</a></h4><p>任何允許<strong>第三方</strong>（除員工和獨立承包商外）透過直接或間接操作存取 Plannotator 功能的商業產品，都屬於受限服務。具體包括但不限於：</p><ul><li><p><strong>雲端服務供應商</strong></p><ul><li>SaaS 平台提供 Plannotator 功能作為其服務的一部分</li><li>託管服務供應商向客戶或訂閱者提供 Plannotator</li></ul></li><li><p><strong>基礎架構服務</strong></p><ul><li>資料中心服務供應商</li><li>雲端運算平台供應商</li></ul></li><li><p><strong>類似服務的第三方</strong></p><ul><li>包括上述實體及其關聯公司提供的任何服務</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">商業使用警告</p><p>如果你計畫將 Plannotator 作為商業服務的一部分提供給第三方使用，必須提前取得商業授權。違反此條款將自動終止你對當前及所有版本 Plannotator 的使用權利。</p></div><h2 id="授權條款變更時程表" tabindex="-1">授權條款變更時程表 <a class="header-anchor" href="#授權條款變更時程表" aria-label="Permalink to &quot;授權條款變更時程表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>時間節點</th><th>授權條款類型</th><th>說明</th></tr></thead><tbody><tr><td><strong>當前 - 2030-01-01</strong></td><td>BSL 1.1</td><td>受限的開源授權條款</td></tr><tr><td><strong>2030-01-01 起</strong></td><td>Apache 2.0</td><td>完全開源，無商業限制</td></tr></tbody></table><h3 id="變更後會發生什麼" tabindex="-1">變更後會發生什麼？ <a class="header-anchor" href="#變更後會發生什麼" aria-label="Permalink to &quot;變更後會發生什麼？&quot;">​</a></h3><p>從 2030 年 1 月 1 日起，Plannotator 將自動轉換為 <strong>Apache License 2.0</strong>。這意味著：</p><ul><li>✅ 所有商業限制將取消</li><li>✅ 可以自由地用於任何商業目的</li><li>✅ 可以將其整合到任何 SaaS 服務中</li><li>✅ 符合寬鬆的開源授權條款標準</li></ul><h2 id="商業授權" tabindex="-1">商業授權 <a class="header-anchor" href="#商業授權" aria-label="Permalink to &quot;商業授權&quot;">​</a></h2><p>如果你需要在不遵守 BSL 限制的情況下使用 Plannotator（例如用於計畫、上下文或審批服務），可以：</p><ol><li><p><strong>購買商業授權</strong></p><ul><li>從 backnotprop 或其授權經銷商購買</li><li>獲得不受 BSL 限制的使用權利</li></ul></li><li><p><strong>聯絡授權方</strong></p><ul><li>發送電子郵件至：backnotprop</li><li>說明你的使用情境和需求</li></ul></li></ol><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="我可以在公司內部使用-plannotator-嗎" tabindex="-1">我可以在公司內部使用 Plannotator 嗎？ <a class="header-anchor" href="#我可以在公司內部使用-plannotator-嗎" aria-label="Permalink to &quot;我可以在公司內部使用 Plannotator 嗎？&quot;">​</a></h3><p><strong>可以。</strong> BSL 明確允許你和你的員工、獨立承包商使用 Plannotator 進行內部開發、測試和部署。限制僅適用於向<strong>第三方</strong>（非員工和承包商）提供服務的情境。</p><h3 id="我可以基於-plannotator-開發自己的產品嗎" tabindex="-1">我可以基於 Plannotator 開發自己的產品嗎？ <a class="header-anchor" href="#我可以基於-plannotator-開發自己的產品嗎" aria-label="Permalink to &quot;我可以基於 Plannotator 開發自己的產品嗎？&quot;">​</a></h3><p><strong>可以，但有條件。</strong> 如果你的產品是：</p><ul><li>內部工具：✅ 允許</li><li>個人專案：✅ 允許</li><li>開源專案：✅ 允許（保留 BSL 授權條款）</li><li>商業產品：❓ 需要評估是否屬於「計畫、上下文或審批服務」</li></ul><h3 id="我的公司是-saas-供應商-可以使用嗎" tabindex="-1">我的公司是 SaaS 供應商，可以使用嗎？ <a class="header-anchor" href="#我的公司是-saas-供應商-可以使用嗎" aria-label="Permalink to &quot;我的公司是 SaaS 供應商，可以使用嗎？&quot;">​</a></h3><p><strong>需要商業授權。</strong> 如果你的 SaaS 產品將 Plannotator 的功能提供給客戶使用（即使作為功能的一部分），這屬於受限的商業服務，必須購買商業授權。</p><h3 id="_2030-年之後我可以將-plannotator-用於任何用途嗎" tabindex="-1">2030 年之後我可以將 Plannotator 用於任何用途嗎？ <a class="header-anchor" href="#_2030-年之後我可以將-plannotator-用於任何用途嗎" aria-label="Permalink to &quot;2030 年之後我可以將 Plannotator 用於任何用途嗎？&quot;">​</a></h3><p><strong>是的。</strong> 從變更日期起，Plannotator 將採用 Apache 2.0 授權條款，所有商業限制都將取消，你可以自由地用於任何用途。</p><h2 id="授權條款完整文字" tabindex="-1">授權條款完整文字 <a class="header-anchor" href="#授權條款完整文字" aria-label="Permalink to &quot;授權條款完整文字&quot;">​</a></h2><p>完整的 Business Source License 1.1 文字請參閱專案根目錄的 <code>LICENSE</code> 檔案。</p><h2 id="聯絡方式" tabindex="-1">聯絡方式 <a class="header-anchor" href="#聯絡方式" aria-label="Permalink to &quot;聯絡方式&quot;">​</a></h2><p>如需商業授權或有其他問題，請聯絡：</p><ul><li><strong>授權方</strong>：backnotprop</li><li><strong>專案儲存庫</strong>：<a href="https://github.com/backnotprop/plannotator" target="_blank" rel="noreferrer">backnotprop/plannotator</a></li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們查看 <strong><a href="./../../changelog/release-notes/">更新日誌</a></strong>。</p><p>你會看到：</p><ul><li>Plannotator 的版本歷史</li><li>每個版本的新功能和改進</li><li>重要的 bug 修復</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>授權條款聲明</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/README.md#L100-L104" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>100-104</td></tr><tr><td>完整授權條款文字</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer"><code>LICENSE</code></a></td><td>1-115</td></tr></tbody></table><p><strong>關鍵資訊</strong>：</p><ul><li>授權條款類型：Business Source License 1.1 (BSL)</li><li>版權方：backnotprop (c) 2025</li><li>變更日期：2030-01-01</li><li>變更後授權條款：Apache License, Version 2.0</li><li>主要限制：不得用於計畫、上下文或審批服務</li></ul></details>',47)])])}const b=a(n,[["render",e]]);export{u as __pageData,b as default};
